"use client";

import "../shared/callout.css";

import { Callout as CalloutRoot, type CalloutProps, type CalloutFrame } from "./callout";
import { CalloutIcon, type CalloutIconProps } from "./callout-icon";
import { CalloutTitle, type CalloutTitleProps } from "./callout-title";
import { CalloutContent, type CalloutContentProps } from "./callout-content";
import { CalloutDismiss, type CalloutDismissProps } from "./callout-dismiss";

const Callout = Object.assign(CalloutRoot, {
  Icon: CalloutIcon,
  Title: CalloutTitle,
  Content: CalloutContent,
  Dismiss: CalloutDismiss,
});

export { Callout, type CalloutProps, type CalloutFrame };
export { type CalloutTone } from "./callout-context";
export { CalloutIcon, type CalloutIconProps };
export { CalloutTitle, type CalloutTitleProps };
export { CalloutContent, type CalloutContentProps };
export { CalloutDismiss, type CalloutDismissProps };

"use client";

import { createContext, useContext } from "react";

export type CalloutTone = "info" | "warning" | "error" | "success";

export interface CalloutContextValue {
  tone: CalloutTone;
  onDismiss: () => void;
}

export const CalloutContext = createContext<CalloutContextValue | undefined>(undefined);

export function useCalloutContext() {
  const context = useContext(CalloutContext);
  if (!context) {
    throw new Error("Callout compound components must be used within a Callout");
  }
  return context;
}

"use client";

import {
  Children,
  isValidElement,
  useCallback,
  useMemo,
  type CSSProperties,
  type HTMLAttributes,
  type ReactNode,
  type Ref,
} from "react";
import { cn } from "@/lib/utils";
import { useControllableState } from "@/hooks/use-controllable-state";
import { CalloutContext, type CalloutTone } from "./callout-context";
import { CalloutIcon } from "./callout-icon";

export type CalloutFrame = "inline" | "rail" | "bar";

const TONE_LABEL: Record<CalloutTone, string> = {
  info: "Info: ",
  warning: "Warning: ",
  error: "Error: ",
  success: "Success: ",
};

const TONE_ROLE_LIVE: Record<CalloutTone, "status" | "alert"> = {
  info: "status",
  warning: "status",
  success: "status",
  error: "alert",
};

function hasCalloutIcon(children: ReactNode): boolean {
  let found = false;
  Children.forEach(children, (child) => {
    if (found) return;
    if (isValidElement(child) && child.type === CalloutIcon) {
      found = true;
    }
  });
  return found;
}

interface GridStyle {
  className: string;
  style: CSSProperties;
}

function gridStyle(frame: CalloutFrame, hasIcon: boolean): GridStyle {
  if (frame === "bar") {
    if (hasIcon) {
      return {
        className: "grid items-start gap-x-[10px] gap-y-1 grid-cols-[4px_16px_minmax(0,1fr)_auto]",
        style: { gridTemplateAreas: "'bar icon title dismiss' 'bar . body .'" },
      };
    }
    return {
      className: "grid items-start gap-x-[10px] gap-y-1 grid-cols-[4px_minmax(0,1fr)_auto]",
      style: { gridTemplateAreas: "'bar title dismiss' 'bar body .'" },
    };
  }
  if (hasIcon) {
    return {
      className: "grid items-start gap-x-[10px] gap-y-1 grid-cols-[16px_minmax(0,1fr)_auto]",
      style: { gridTemplateAreas: "'icon title dismiss' '. body .'" },
    };
  }
  return {
    className: "grid items-start gap-x-[10px] gap-y-1 grid-cols-[minmax(0,1fr)_auto]",
    style: { gridTemplateAreas: "'title dismiss' 'body .'" },
  };
}

export interface CalloutProps extends HTMLAttributes<HTMLDivElement> {
  children: ReactNode;
  tone?: CalloutTone;
  frame?: CalloutFrame;
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  /**
   * When true, applies role="status" (or role="alert" for error tone) so
   * assistive tech announces the message. Default false: no role.
   */
  live?: boolean;
  ref?: Ref<HTMLDivElement>;
}

export function Callout({
  className,
  tone = "info",
  frame = "inline",
  open: controlledOpen,
  defaultOpen,
  onOpenChange,
  live = false,
  ref,
  children,
  ...props
}: CalloutProps) {
  const [open, setOpen] = useControllableState({
    value: controlledOpen,
    defaultValue: defaultOpen ?? true,
    onChange: onOpenChange,
  });

  const onDismiss = useCallback(() => setOpen(false), [setOpen]);
  const contextValue = useMemo(() => ({ tone, onDismiss }), [tone, onDismiss]);

  if (!open) return null;

  const hasIcon = hasCalloutIcon(children);
  const role = live ? TONE_ROLE_LIVE[tone] : undefined;
  const grid = gridStyle(frame, hasIcon);

  return (
    <CalloutContext value={contextValue}>
      <div
        ref={ref}
        role={role}
        data-slot="callout"
        data-tone={tone}
        data-frame={frame}
        className={cn(className)}
        {...props}
      >
        <div className={grid.className} style={grid.style}>
          {frame === "bar" && (
            <span
              aria-hidden="true"
              style={{ gridArea: "bar" }}
              className="self-stretch w-1 rounded-[1px] bg-[color:var(--cal-tone)] forced-colors:bg-[CanvasText]"
            />
          )}
          <span className="sr-only">{TONE_LABEL[tone]}</span>
          {children}
        </div>
      </div>
    </CalloutContext>
  );
}

"use client";

import type { HTMLAttributes, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { type CalloutTone, useCalloutContext } from "./callout-context";

const DEFAULT_ICON: Record<CalloutTone, ReactNode> = {
  info: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <circle cx="8" cy="8" r="7" />
      <path d="M8 5v4M8 11h.01" />
    </svg>
  ),
  warning: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <path d="M8 1.5L15 14H1L8 1.5z" />
      <path d="M8 6v4M8 12h.01" />
    </svg>
  ),
  error: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <circle cx="8" cy="8" r="7" />
      <path d="M5 5l6 6M11 5l-6 6" />
    </svg>
  ),
  success: (
    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
      <circle cx="8" cy="8" r="7" />
      <path d="M5 8.5l2 2 4-5" />
    </svg>
  ),
};

export interface CalloutIconProps extends HTMLAttributes<HTMLSpanElement> {
  children?: ReactNode;
}

export function CalloutIcon({ children, className, style, ...props }: CalloutIconProps) {
  const { tone } = useCalloutContext();

  return (
    <span
      aria-hidden="true"
      style={{ gridArea: "icon", ...style }}
      className={cn(
        "inline-flex items-center justify-center self-center w-4 h-4 text-[color:var(--cal-tone)] [&>svg]:w-[14px] [&>svg]:h-[14px]",
        className,
      )}
      {...props}
    >
      {children ?? DEFAULT_ICON[tone]}
    </span>
  );
}

"use client";

import type { HTMLAttributes, ReactNode } from "react";
import { cn } from "@/lib/utils";

export interface CalloutTitleProps extends HTMLAttributes<HTMLSpanElement> {
  children: ReactNode;
}

export function CalloutTitle({ children, className, style, ...props }: CalloutTitleProps) {
  return (
    <span
      style={{ gridArea: "title", ...style }}
      className={cn(
        "self-center font-bold text-[13px] leading-[1.4] text-[color:var(--cal-tone)]",
        className,
      )}
      {...props}
    >
      {children}
    </span>
  );
}

"use client";

import type { HTMLAttributes, ReactNode } from "react";
import { cn } from "@/lib/utils";

export interface CalloutContentProps extends HTMLAttributes<HTMLDivElement> {
  children: ReactNode;
}

export function CalloutContent({ children, className, style, ...props }: CalloutContentProps) {
  return (
    <div
      style={{ gridArea: "body", ...style }}
      className={cn(
        "text-[12px] leading-[1.55] text-muted-foreground",
        className,
      )}
      {...props}
    >
      {children}
    </div>
  );
}

"use client";

import type { ButtonHTMLAttributes, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useCalloutContext } from "./callout-context";

export interface CalloutDismissProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  children?: ReactNode;
}

export function CalloutDismiss({
  children,
  className,
  onClick,
  style,
  ...props
}: CalloutDismissProps) {
  const { onDismiss } = useCalloutContext();

  return (
    <button
      type="button"
      aria-label="Dismiss"
      style={{ gridArea: "dismiss", ...style }}
      onClick={(e) => {
        onClick?.(e);
        if (!e.defaultPrevented) onDismiss();
      }}
      className={cn(
        "self-center inline-flex items-center justify-center shrink-0",
        "w-6 h-6 p-1 rounded-[var(--radius)] font-mono text-[13px] cursor-pointer",
        "text-muted hover:text-foreground hover:bg-foreground/5",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[color:var(--cal-tone)] focus-visible:ring-offset-2 focus-visible:ring-offset-background",
        "transition-colors",
        className,
      )}
      {...props}
    >
      {children ?? "[x]"}
    </button>
  );
}
